SELECT AVG(pass_rate) AS average_pass_rate
  FROM course_statistics
  WHERE enrollment_count > 50;

SELECT COUNT(*) AS online_course_count
FROM course_locations
WHERE location_type = 'online';

SELECT AVG(rating) AS average_rating
FROM course_reviews
WHERE course_id = 1;

SELECT course_name
FROM courses
ORDER BY course_name;

SELECT course_id
FROM course_statistics
WHERE enrollment_count > 150 AND pass_rate > 0.85;

SELECT course_name
FROM courses
ORDER BY course_name;

SELECT course_name
FROM courses
ORDER BY course_name;
